+				return t.Response.Meta.Timestamp
+			}
+			if t.Request != nil {
+				return t.Request.Meta.Timestamp
+			}
+			return time.Time{}
 		}
-		return turns[i].Request.Meta.Timestamp.Before(turns[j].Request.Meta.Timestamp)
+		return getTime(turns[i]).Before(getTime(turns[j]))
 	})

 	return turns

